import{_ as a,o as e,c as r,a7 as o}from"./chunks/framework.C5fSpjcB.js";const _=JSON.parse('{"title":"相位对弈（PvP）","description":"","frontmatter":{},"headers":[],"relativePath":"modes/phase-chess.md","filePath":"zh/modes/phase-chess.md","lastUpdated":1775394001000}'),s={name:"modes/phase-chess.md"};function d(l,t,n,i,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="相位对弈-pvp" tabindex="-1">相位对弈（PvP） <a class="header-anchor" href="#相位对弈-pvp" aria-label="Permalink to &quot;相位对弈（PvP）&quot;">​</a></h1><p>相位对弈是忘却前夜的 PvP 对战模式，强调纯粹的卡牌构筑技巧。</p><h2 id="解锁条件" tabindex="-1">解锁条件 <a class="header-anchor" href="#解锁条件" aria-label="Permalink to &quot;解锁条件&quot;">​</a></h2><p>通关主线 <strong>3-2</strong> 关卡后解锁。</p><h2 id="基本规则" tabindex="-1">基本规则 <a class="header-anchor" href="#基本规则" aria-label="Permalink to &quot;基本规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>规则</th><th>数值</th></tr></thead><tbody><tr><td>初始能量</td><td>3</td></tr><tr><td>每回合能量增加</td><td>+1</td></tr><tr><td>最大能量</td><td>10</td></tr><tr><td>每回合抽牌</td><td>5 张</td></tr><tr><td>手牌上限</td><td>10 张</td></tr></tbody></table><h2 id="公平性" tabindex="-1">公平性 <a class="header-anchor" href="#公平性" aria-label="Permalink to &quot;公平性&quot;">​</a></h2><p>相位对弈的核心特点是 <strong>完全公平</strong>：</p><ul><li><strong>无角色数值差异</strong> - 所有角色的属性在PvP中统一</li><li><strong>无装备影响</strong> - 命轮、密契等装备效果不生效</li><li><strong>纯构筑竞技</strong> - 完全依靠卡牌构筑和操作技巧</li></ul><h2 id="竞技建议" tabindex="-1">竞技建议 <a class="header-anchor" href="#竞技建议" aria-label="Permalink to &quot;竞技建议&quot;">​</a></h2><ol><li><strong>适应能量曲线</strong> - 前期能量少，打低费卡；后期能量多，打高费combo</li><li><strong>针对性构筑</strong> - 了解当前热门构筑，准备应对方案</li><li><strong>手牌管理</strong> - 注意10张手牌上限，避免爆牌</li><li><strong>节奏把控</strong> - 在合适时机发动攻势</li></ol>',11)])])}const g=a(s,[["render",d]]);export{_ as __pageData,g as default};
